#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char S[201];
        scanf("%s", S);
        int freq[256] = {0};
        for (int i = 0; S[i] != '\0'; ++i) {
            freq[(unsigned char)S[i]]++;
        }
        int cost = 0;
        for (int i = 0; i < 256; ++i) {
            cost += (freq[i] + 1) / 2;
        }
        printf("%d\n", cost);
    }
    return 0;
}

