import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        for (int t = 0; t < T; ++t) {
            String S = br.readLine();
            while (S != null && S.isEmpty()) S = br.readLine(); // skip possible empty lines
            int[] freq = new int[256];
            for (char c : S.toCharArray()) freq[(int) c]++;
            int cost = 0;
            for (int i = 0; i < 256; ++i) cost += (freq[i] + 1) / 2;
            sb.append(cost).append('\n');
        }
        System.out.print(sb.toString());
    }
}

code.JavaScript:
const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const T = parseInt(lines[idx++], 10);
let results = [];
for (let t = 0; t < T; ++t) {
  const S = lines[idx++] || '';
  const freq = new Array(256).fill(0);
  for (let i = 0; i < S.length; ++i) {
    freq[S.charCodeAt(i)]++;
  }
  let cost = 0;
  for (let i = 0; i < 256; ++i) {
    cost += Math.floor((freq[i] + 1) / 2);
  }
  results.push(cost.toString());
}
console.log(results.join('\n'));
